sourceQuery.expr:
max(
  1 -
  sum by (name) (
    delta(system.cpu.time.idle{host.name="$host_name"}[$__rate_interval])
  )
  /
  sum by (name) (
    delta(
      {__name__=~"system\\.cpu\\.time\\.(idle|user|system|nice|io_wait)", host.name="$host_name"}[$__rate_interval]
    )
  )
)

sum by (network.interface.name) (
  rate(system.network.io.{host.name="$host_name"}[$__rate_interval])
  +
  ignoring(network.io.direction)
  rate(system.network.io.transmit{host.name="$host_name"}[$__rate_interval])
)

max(
  (
    sum by (network.interface.name) (
			rate(system.network.io.receive{host.name="$host_name"}[$__rate_interval])
			+
			ignoring(network.io.direction)
			rate(system.network.io.transmit{host.name="$host_name"}[$__rate_interval])
		)
  )
  /
  (
    max by (network.interface.name) (
      system.network.bandwidth.limit{host.name="$host_name"}
    )
  )
)

max(
  (
    sum by (network.interface.name) (
      rate(system.network.io.receive{host.name="$host_name"}[$__rate_interval])
      +
      ignoring(network.io.direction)
      rate(system.network.io.transmit{host.name="$host_name"}[$__rate_interval])
    )
  )
  /
  (
    max by (network.interface.name) (
      system.network.bandwidth.limit{host.name="$host_name"}
    )
  )
)
